def main():
    """Main entry point for the PostgreSQL admin tool."""
    print("PostgreSQL Extension Manager")
    print("-" * 40)

    host = input("Database host [localhost]: ").strip() or "localhost"
    port_str = input("Database port [5432]: ").strip() or "5432"
    try:
        port = int(port_str)
    except ValueError:
        print("Invalid port number. Using default 5432.")
        port = 5432

    dbname = input("Database name [postgres]: ").strip() or "postgres"
    user = input("Database user [postgres]: ").strip() or "postgres"
    password = getpass.getpass("Database password: ")

    try:
        conn = get_db_connection(host, port, dbname, user, password)
        print(f"\n[CONNECTED] Successfully connected to '{dbname}' on {host}:{port}")
    except psycopg2.Error as e:
        print(f"[ERROR] Could not connect to database: {e}")
        return

    try:
        while True:
            print_menu()
            choice = input("Select an option (1-6): ").strip()

            if choice == "1":
                extensions = list_installed_extensions(conn)
                print(f"\n{'Extension':<30} {'Version':<15}")
                print("-" * 45)
                for ext_name, ext_version in extensions:
                    print(f"{ext_name:<30} {ext_version:<15}")
                if not extensions:
                    print("  No extensions installed.")

            elif choice == "2":
                extensions = list_available_extensions(conn)
                print(f"\n{'Extension':<30} {'Version':<15} {'Description'}")
                print("-" * 80)
                for name, version, comment in extensions:
                    desc = (comment or "")[:40]
                    print(f"{name:<30} {version or 'N/A':<15} {desc}")

            elif choice == "3":
                ext_name = input("Enter extension name to install: ").strip()
                try:
                    install_extension(conn, ext_name)
                except ValueError as e:
                    print(f"[VALIDATION ERROR] {e}")

            elif choice == "4":
                ext_name = input("Enter extension name to uninstall: ").strip()
                confirm = input(
                    f"Are you sure you want to uninstall '{ext_name}'? "
                    "This will CASCADE drop dependent objects. (yes/no): "
                ).strip().lower()
                if confirm == "yes":
                    try:
                        uninstall_extension(conn, ext_name)
                    except ValueError as e:
                        print(f"[VALIDATION ERROR] {e}")
                else:
                    print("Uninstall cancelled.")

            elif choice == "5":
                print("\nAllowed extensions (whitelist):")
                print("-" * 40)
                for ext in sorted(ALLOWED_EXTENSIONS):
                    print(f"  - {ext}")

            elif choice == "6":
                print("Exiting. Goodbye!")
                break

            else:
                print("Invalid option. Please select 1-6.")

    except KeyboardInterrupt:
        print("\n\nInterrupted. Exiting.")
    finally:
        if conn and not conn.closed:
            conn.close()
            print("[DISCONNECTED] Database connection closed.")


if __name__ == "__main__":
    main()